const data = $input.first().json;
const parts = Array.isArray(data) ? data : (data?.results || []);

if (parts.length === 0) {
  return [{ json: { skip: true, count: 0 } }];
}

// Analyze each part: stock level vs minimum_stock (reorder level)
const predictions = parts.map(p => {
  const stock = p.in_stock || 0;
  const reorder = p.minimum_stock || 0;
  const ratio = reorder > 0 ? stock / reorder : 999;
  let urgency = 'OK';
  if (stock <= 0) urgency = 'OUT OF STOCK';
  else if (stock <= reorder) urgency = 'REORDER NOW';
  else if (ratio <= 2) urgency = 'REORDER SOON';

  return {
    name: p.name || p.IPN || 'Unknown',
    stock,
    reorderLevel: reorder,
    urgency,
    ratio: +ratio.toFixed(1)
  };
}).filter(p => p.urgency !== 'OK')
  .sort((a, b) => a.ratio - b.ratio);

if (predictions.length === 0) {
  return [{ json: { skip: true, count: 0 } }];
}

const lines = predictions.map(p =>
  `${p.urgency === 'OUT OF STOCK' ? '🔴' : p.urgency === 'REORDER NOW' ? '🟡' : '🟢'} ${p.name} — stock: ${p.stock}, reorder at: ${p.reorderLevel} [${p.urgency}]`
).join('\n');

return [{ json: {
  skip: false,
  count: predictions.length,
  outOfStock: predictions.filter(p => p.urgency === 'OUT OF STOCK').length,
  reorderNow: predictions.filter(p => p.urgency === 'REORDER NOW').length,
  reorderSoon: predictions.filter(p => p.urgency === 'REORDER SOON').length,
  body: lines
} }];

